VALUES
  ('disabled-6f0ba476-moex-00341', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '關於課稅與超額負擔間之關係，下列敘述何者正確？', '["如果課稅後，商品的相對價格不變，表示不會產生超額負擔", "如果課稅後，對某項商品的需求數量不變，表示不會產生超額負擔", "如果對單一商品課稅後產生的替代效果與所得效果相互抵消，表示不會 產生超額負擔", "如果對單一商品課稅後，僅產生替代效果，沒有所得效果，表示不會產 生超額負擔"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "fde2e91d440b", "answer_pdf_sha1": "a2fe5f50ed5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00342', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '若某一財貨由邊際成本固定的完全競爭市場提供，該財貨未受補償需求曲 線為負斜率，受補償需求曲線為垂直線。若政府對市場供給者課徵從量稅， 關於課稅經濟效果之敘述，下列何者正確？', '["有價格效果，無所得效果", "有替代效果，無所得效果", "有價格效果，無替代效果", "有替代效果，無價格效果"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "fde2e91d440b", "answer_pdf_sha1": "a2fe5f50ed5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00343', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '當勞動市場為完全競爭時，如果甲在公司工作，其勞務必須課徵從價的薪 資稅，但在家工作卻免稅，此種情況會造成什麼結果？', '["不會扭曲甲在部門間的選擇", "當稅前與稅後的工資率差距越大，則超額負擔越大", "當稅前與稅後的均衡勞動量差距越大，則超額負擔越小", "當一種要素在不同用途上被課不同的稅，則不會產生超額負擔"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "fde2e91d440b", "answer_pdf_sha1": "a2fe5f50ed5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00344', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '若社會福利函數為勞爾斯（Rawlsian）社會福利函數，每人偏好只和所得 有關，每人所得不同，總所得固定不變。關於最適租稅的設計，下列何者 正確？', '["應採用較累進的所得稅制", "應對任何所得水準皆課單一稅率的所得稅", "應對需求較無彈性的必需品課較高的稅率", "應對較容易上癮的財貨（例如菸酒）課較重的租稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "fde2e91d440b", "answer_pdf_sha1": "a2fe5f50ed5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00345', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '假設啤酒和碳酸飲料為完全互補品，且政府只針對啤酒課徵貨物稅，下列 敘述何者正確？', '["針對啤酒課稅產生的所得效果造成無謂損失", "針對啤酒課稅產生的替代效果造成無謂損失", "以定額稅取代啤酒稅的課徵可減少無謂損失", "課徵定額稅或啤酒稅都不會產生無謂損失"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "fde2e91d440b", "answer_pdf_sha1": "a2fe5f50ed5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00346', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '關於Edgeworth最適所得稅模型之敘述，下列何者正確？', '["假設個人可以選擇所得與休閒", "當所得相同時邊際效用會相同", "對最高所得個人的邊際稅率為零", "社會可獲取的所得總量是不固定的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "fde2e91d440b", "answer_pdf_sha1": "a2fe5f50ed5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00347', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '在兩期生命循環週期模型中，如果政府可以對休閒課稅，下列那些租稅具', '["對所有財貨（包括休閒）課徵比例稅", "對休閒之外的所有 財貨課徵比例稅", "對兩期所得課徵比例稅", "定額稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "fde2e91d440b", "answer_pdf_sha1": "a2fe5f50ed5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00348', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '小型開放經濟體系內，資本市場資金的來源包含本國儲蓄以及外國世界市 場資金。如果政府對本國儲蓄課稅，會導致下列那項效果？', '["本國儲蓄者供給之資金數量增加", "本國儲蓄者供給之資金數量減少", "本國資金借貸者必須付出較高利率", "本國資金借貸者必須付出較低利率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "fde2e91d440b", "answer_pdf_sha1": "a2fe5f50ed5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00349', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '個人所得稅率越高，其對風險性資產的投資誘因會有何影響？', '["增加", "減少", "不一定", "無關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "fde2e91d440b", "answer_pdf_sha1": "a2fe5f50ed5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00350', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '甲、乙慈善捐款的價格彈性分別為1.2與2，所得稅的邊際稅率均為40%。 在慈善捐款不得列入所得扣除額時，甲、乙的慈善捐贈金額各為 10 萬元 與 20 萬元。若慈善捐款可以全額列入扣除額，甲、乙慈善捐款共會增加 多少元？', '["3萬2千元", "12萬元", "16萬元6千元", "20萬8千元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "fde2e91d440b", "answer_pdf_sha1": "a2fe5f50ed5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
